/**
 * Pure validation functions for order operations.
 *
 * These validators contain no side effects and no database calls.
 * They receive pre-fetched data and validate business rules.
 */

import type { OrderItem, OrderStatus } from '../models/order.js';
import type { User } from '../models/user.js';

/**
 * Valid status transitions for orders.
 */
const STATUS_TRANSITIONS: Record<OrderStatus, OrderStatus[]> = {
  pending: ['confirmed', 'cancelled'],
  confirmed: ['shipped', 'cancelled'],
  shipped: ['delivered'],
  delivered: [],
  cancelled: [],
};

/**
 * Check whether a status transition is allowed.
 */
export function isValidStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): boolean {
  return STATUS_TRANSITIONS[from].includes(to);
}

/**
 * Validate a status transition, throwing if invalid.
 */
export function validateStatusTransition(
  from: OrderStatus,
  to: OrderStatus,
): void {
  if (!isValidStatusTransition(from, to)) {
    throw new Error(`Invalid status transition: ${from} -> ${to}`);
  }
}

/**
 * Validate that order items are non-empty.
 */
export function validateOrderItems(items: OrderItem[]): void {
  if (items.length === 0) {
    throw new Error('Order must have at least one item');
  }
}

/**
 * Validate that a user exists (for order creation).
 */
export function validateOrderUser(
  user: User | undefined,
  userId: string,
): void {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Validate that an order exists.
 */
export function validateOrderExists<T>(
  order: T | undefined,
  orderId: string,
): asserts order is T {
  if (!order) {
    throw new Error(`Order not found: ${orderId}`);
  }
}

/**
 * Pure validation functions for user operations.
 *
 * These validators contain no side effects and no database calls.
 * They receive pre-fetched data and validate business rules.
 */

import type { User } from '../models/user.js';

/**
 * Validate that no user already exists with the given email.
 * Used during user creation.
 */
export function validateEmailUnique(
  email: string,
  existingUser: User | undefined,
): void {
  if (existingUser) {
    throw new Error(`User with email ${email} already exists`);
  }
}

/**
 * Validate that an email is not already taken by another user.
 * Used during user update when email is being changed.
 */
export function validateEmailNotTaken(
  email: string,
  existingUser: User | undefined,
): void {
  if (existingUser) {
    throw new Error(`Email ${email} is already in use`);
  }
}

/**
 * Validate that a user exists, throwing if not found.
 */
export function validateUserExists<T>(
  user: T | undefined,
  userId: string,
): asserts user is T {
  if (!user) {
    throw new Error(`User not found: ${userId}`);
  }
}

/**
 * Pure validation functions for preferences operations.
 *
 * These validators contain no side effects and no database calls.
 * They receive pre-fetched data and validate business rules.
 */

import type { UserPreferences } from '../models/user-preferences.js';

/**
 * Validate that preferences do not already exist for a user.
 * Used during preference creation.
 */
export function validatePreferencesNotExist(
  existing: UserPreferences | undefined,
  userId: string,
): void {
  if (existing) {
    throw new Error(`Preferences already exist for user: ${userId}`);
  }
}

/**
 * Validate that preferences exist for a user.
 * Used during preference update and deletion.
 */
export function validatePreferencesExist(
  existing: UserPreferences | undefined,
  userId: string,
): asserts existing is UserPreferences {
  if (!existing) {
    throw new Error(`Preferences not found for user: ${userId}`);
  }
}

