import { describe, it, expect } from 'vitest';
import {
  isValidStatusTransition,
  validateStatusTransition,
  validateOrderItems,
  validateOrderUser,
  validateOrderExists,
} from '../../src/validators/order.validator.js';
import type { User } from '../../src/models/user.js';
import type { Order } from '../../src/models/order.js';

describe('order.validator', () => {
  describe('isValidStatusTransition', () => {
    it('should allow pending -> confirmed', () => {
      expect(isValidStatusTransition('pending', 'confirmed')).toBe(true);
    });

    it('should allow pending -> cancelled', () => {
      expect(isValidStatusTransition('pending', 'cancelled')).toBe(true);
    });

    it('should allow confirmed -> shipped', () => {
      expect(isValidStatusTransition('confirmed', 'shipped')).toBe(true);
    });

    it('should allow confirmed -> cancelled', () => {
      expect(isValidStatusTransition('confirmed', 'cancelled')).toBe(true);
    });

    it('should allow shipped -> delivered', () => {
      expect(isValidStatusTransition('shipped', 'delivered')).toBe(true);
    });

    it('should reject pending -> delivered', () => {
      expect(isValidStatusTransition('pending', 'delivered')).toBe(false);
    });

    it('should reject pending -> shipped', () => {
      expect(isValidStatusTransition('pending', 'shipped')).toBe(false);
    });

    it('should reject delivered -> any', () => {
      expect(isValidStatusTransition('delivered', 'pending')).toBe(false);
      expect(isValidStatusTransition('delivered', 'cancelled')).toBe(false);
    });

    it('should reject cancelled -> any', () => {
      expect(isValidStatusTransition('cancelled', 'pending')).toBe(false);
      expect(isValidStatusTransition('cancelled', 'confirmed')).toBe(false);
    });

    it('should reject shipped -> cancelled', () => {
      expect(isValidStatusTransition('shipped', 'cancelled')).toBe(false);
    });
  });

  describe('validateStatusTransition', () => {
    it('should not throw for valid transitions', () => {
      expect(() => validateStatusTransition('pending', 'confirmed')).not.toThrow();
    });

    it('should throw for invalid transitions', () => {
      expect(() => validateStatusTransition('pending', 'delivered')).toThrow(
        'Invalid status transition: pending -> delivered',
      );
    });

    it('should throw for transitions from terminal states', () => {
      expect(() => validateStatusTransition('cancelled', 'confirmed')).toThrow(
        'Invalid status transition: cancelled -> confirmed',
      );
    });
  });

  describe('validateOrderItems', () => {
    it('should not throw for non-empty items', () => {
      expect(() =>
        validateOrderItems([
          { productId: 'p1', name: 'Widget', quantity: 1, unitPrice: 10 },
        ]),
      ).not.toThrow();
    });

    it('should throw for empty items', () => {
      expect(() => validateOrderItems([])).toThrow(
        'Order must have at least one item',
      );
    });
  });

  describe('validateOrderUser', () => {
    it('should not throw when user exists', () => {
      const user: User = {
        id: 'user-1',
        name: 'Alice',
        email: 'alice@example.com',
        role: 'member',
        createdAt: new Date(),
        updatedAt: new Date(),
      };
      expect(() => validateOrderUser(user, 'user-1')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateOrderUser(undefined, 'user-99')).toThrow(
        'User not found: user-99',
      );
    });
  });

  describe('validateOrderExists', () => {
    it('should not throw when order exists', () => {
      const order = { id: 'order-1' } as Order;
      expect(() => validateOrderExists(order, 'order-1')).not.toThrow();
    });

    it('should throw when order is undefined', () => {
      expect(() => validateOrderExists(undefined, 'order-99')).toThrow(
        'Order not found: order-99',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validateEmailUnique,
  validateEmailNotTaken,
  validateUserExists,
} from '../../src/validators/user.validator.js';
import type { User } from '../../src/models/user.js';

const makeUser = (overrides: Partial<User> = {}): User => ({
  id: 'user-1',
  name: 'Alice',
  email: 'alice@example.com',
  role: 'member',
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('user.validator', () => {
  describe('validateEmailUnique', () => {
    it('should not throw when no existing user', () => {
      expect(() => validateEmailUnique('new@example.com', undefined)).not.toThrow();
    });

    it('should throw when user with email already exists', () => {
      const existing = makeUser({ email: 'taken@example.com' });
      expect(() => validateEmailUnique('taken@example.com', existing)).toThrow(
        'User with email taken@example.com already exists',
      );
    });
  });

  describe('validateEmailNotTaken', () => {
    it('should not throw when email is available', () => {
      expect(() => validateEmailNotTaken('free@example.com', undefined)).not.toThrow();
    });

    it('should throw when email is already in use', () => {
      const existing = makeUser({ email: 'taken@example.com' });
      expect(() => validateEmailNotTaken('taken@example.com', existing)).toThrow(
        'Email taken@example.com is already in use',
      );
    });
  });

  describe('validateUserExists', () => {
    it('should not throw when user exists', () => {
      const user = makeUser();
      expect(() => validateUserExists(user, 'user-1')).not.toThrow();
    });

    it('should throw when user is undefined', () => {
      expect(() => validateUserExists(undefined, 'user-99')).toThrow(
        'User not found: user-99',
      );
    });
  });
});

import { describe, it, expect } from 'vitest';
import {
  validatePreferencesNotExist,
  validatePreferencesExist,
} from '../../src/validators/preferences.validator.js';
import type { UserPreferences } from '../../src/models/user-preferences.js';

const makePreferences = (overrides: Partial<UserPreferences> = {}): UserPreferences => ({
  id: 'pref-0001',
  userId: 'user-1',
  email: {
    enabled: true,
    frequency: 'instant',
    subscribedCategories: ['order_confirmation', 'order_status_update'],
  },
  createdAt: new Date(),
  updatedAt: new Date(),
  ...overrides,
});

describe('preferences.validator', () => {
  describe('validatePreferencesNotExist', () => {
    it('should not throw when no existing preferences', () => {
      expect(() => validatePreferencesNotExist(undefined, 'user-1')).not.toThrow();
    });

    it('should throw when preferences already exist', () => {
      const existing = makePreferences();
      expect(() => validatePreferencesNotExist(existing, 'user-1')).toThrow(
        'Preferences already exist for user: user-1',
      );
    });
  });

  describe('validatePreferencesExist', () => {
    it('should not throw when preferences exist', () => {
      const existing = makePreferences();
      expect(() => validatePreferencesExist(existing, 'user-1')).not.toThrow();
    });

    it('should throw when preferences are undefined', () => {
      expect(() => validatePreferencesExist(undefined, 'user-99')).toThrow(
        'Preferences not found for user: user-99',
      );
    });
  });
});

